INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(4, 1, '05', 'Porter 개발자', 'Porter의 5 Forces 모델을 개발한 학자는?', '피터 드러커', '워런 버핏', '마이클 포터(Harvard)', '벤저민 그레이엄', 2, '문서에 Porter의 5 Forces는 마이클 포터(Harvard)가 개발한 산업 경쟁강도 분석 도구라고 명시되어 있습니다.'),
(4, 2, '05', 'Porter 5 Forces 구성', 'Porter의 5 Forces에 포함되지 않는 항목은?', '신규 진입자 위협', '공급자 협상력', '정부 규제 압력', '대체재 위협', 2, '문서의 5가지 경쟁 압력은 신규 진입자 위협, 공급자 협상력, 구매자 협상력, 대체재 위협, 기존 경쟁자 간 경쟁입니다. 정부 규제 압력은 Porter 5 Forces에 포함되지 않습니다.'),
(4, 3, '05', '산업 매력도 방향', 'Porter의 5 Forces에서 신규 진입자 위협이 낮을수록 산업 매력도는?', '낮아진다', '높아진다', '변화 없다', '불확실해진다', 1, '문서 표에서 신규 진입자 위협은 낮을수록 좋음(높은 진입장벽)으로 설명되며, 위협이 낮을수록 산업 매력도가 높아집니다.'),
(4, 4, '05', '반도체 진입장벽', '반도체 산업에서 신규 진입자 위협이 낮은 주요 이유로 문서에 제시된 것은?', '수요가 너무 적어 이익이 없음', '수십조 원의 팹 투자와 기술 장벽', '정부 보조금 부재', '노동비용 과다', 1, '문서의 반도체 Porter 5 Forces 표에서 신규 진입자 위협이 낮은 이유로 수십조 원의 팹 투자, 기술 장벽이 제시됩니다.'),
(4, 5, '05', '반도체 공급자 협상력', '반도체 산업에서 공급자 협상력 수준과 이유로 문서와 일치하는 것은?', '낮음 - 공급사가 많아 경쟁 과열', '중간~높음 - 희귀 소재·장비 독점(ASML 등)', '낮음 - 범용 소재만 사용', '매우 낮음 - 자체 소재 생산', 1, '문서 표에서 반도체 공급자 협상력은 중간~높음이며, 이유는 희귀 소재·장비 독점(ASML 등)입니다.'),
(4, 6, '05', 'Porter API 점수 척도', '문서의 Porter 5 Forces API에서 점수(scores)의 척도 범위는?', '0~5 (낮은 위협=0)', '0~100 (백분율)', '0~10 (위협 없음=0, 위협 극대=10)', '1~5 (리커트 척도)', 2, '문서에 scores의 각 값은 0(위협 없음)~10(위협 극대) 척도라고 명시되어 있습니다.'),
(4, 7, '05', 'SWOT 내부 요소', 'SWOT 분석에서 내부 역량에 해당하는 항목은?', 'Opportunity(기회)와 Threat(위협)', 'Strength(강점)와 Weakness(약점)', 'Political과 Economic', 'Social과 Technological', 1, '문서에서 SWOT는 내부 역량(S·W)과 외부 환경(O·T)을 매트릭스로 정리한다고 설명합니다.'),
(4, 8, '05', 'SWOT 외부 요소', 'SWOT에서 외부 환경에 해당하는 항목으로 맞는 것은?', 'Strength와 Weakness', 'Opportunity와 Threat', 'Strength와 Opportunity', 'Weakness와 Threat', 1, '문서에서 외부 환경은 O(Opportunity, 기회)와 T(Threat, 위협)로 구성됩니다.'),
(4, 9, '05', 'PEST P 요소', 'PEST 분석에서 P(Political) 투자 관련 예시로 문서에 제시된 것은?', '금리 변동, 환율 리스크', '반도체 수출규제, 바이오 허가 규제', 'AI 수요 급증, EV 전환', '고령화, MZ 소비 패턴', 1, '문서 표에서 P(Political)의 투자 관련 예시로 반도체 수출규제, 바이오 허가 규제가 제시됩니다.'),
(4, 10, '05', 'PEST E 요소', 'PEST 분석에서 E(Economic) 요소로 제시된 것은?', '탄소 중립 정책', '반도체 미세화 한계', '금리, 환율, 경기 사이클', 'ESG 투자 확대', 2, '문서 표에서 E(Economic) 요소는 금리, 환율, 경기 사이클로 설명됩니다.'),
(4, 11, '05', 'PEST S 요소', 'PEST 분석에서 S(Social) 요소의 투자 관련 예시는?', 'AI 수요 급증', '고령화(헬스케어↑), MZ 소비 패턴', '반도체 수출규제', '기준금리 인상', 1, '문서 표에서 S(Social) 요소는 고령화(헬스케어↑), MZ 소비 패턴으로 제시됩니다.'),
(4, 12, '05', '산업 수명주기 순서', '산업 수명주기의 올바른 순서는?', '성장기 → 도입기 → 성숙기 → 쇠퇴기', '도입기 → 성장기 → 성숙기 → 쇠퇴기', '성숙기 → 성장기 → 도입기 → 쇠퇴기', '도입기 → 성숙기 → 성장기 → 쇠퇴기', 1, '문서의 산업 수명주기는 도입기 → 성장기 → 성숙기 → 쇠퇴기 순으로 진행됩니다.'),
(4, 13, '05', '도입기 주의점', '산업 수명주기 도입기(Introduction)의 투자 시 주의점으로 맞는 것은?', '안정적 이익과 고배당 기대', '멀티플 수렴 고려', '실패 위험 높음, 소수 선도 기업에 집중', '특별 상황 투자(자산가치) 추구', 2, '문서에서 도입기 투자 시 주의점은 실패 위험이 높으며 소수 선도 기업에 집중한다고 설명합니다.'),
(4, 14, '05', '성장기 특징', '성장기(Growth) 특징으로 문서와 일치하는 것은?', '매출 급증과 경쟁자 유입', '안정적 이익과 고배당', '매출 하락과 구조조정', '적자와 높은 성장 잠재력', 0, '문서에서 성장기는 매출 급증과 경쟁자 유입이 특징으로 설명됩니다.'),
(4, 15, '05', '성숙기 투자 포인트', '성숙기(Maturity)에서 문서가 강조하는 투자 포인트는?', '높은 PER로 성장 정당화', '실패 위험 최소화에 집중', '배당수익률 중요', '자산가치 특별 상황 추구', 2, '문서에서 성숙기는 멀티플 수렴이 일어나며 배당수익률이 중요하다고 강조합니다.'),
(4, 16, '05', '쇠퇴기 특징', '쇠퇴기(Decline) 특징으로 문서에 제시된 것은?', '매출 급증·경쟁자 유입', '안정적 이익·고배당', '매출 하락·구조조정', '적자·높은 성장 잠재력', 2, '문서에서 쇠퇴기는 매출 하락과 구조조정이 특징으로, 특별 상황 투자(자산 가치) 외에는 일반 투자자가 기피한다고 설명합니다.'),
(4, 17, '05', '수명주기 API', '산업 수명주기 분석 API 엔드포인트와 메서드는?', 'GET /api/industry/lifecycle', 'POST /api/industry/lifecycle', 'GET /api/industry/porter', 'PUT /api/industry/life', 1, '문서에 수명주기 분석 API는 POST /api/industry/lifecycle로 설계되어 있습니다.'),
(4, 18, '05', '반도체 ASP 지표', '반도체 산업에서 ASP(평균판매가격) 지표의 주요 활용 목적은?', '공장 가동 효율 측정', '메모리 가격 사이클 파악', '차세대 설비투자 방향 파악', 'EV 침투율 추적', 1, '문서 표에서 ASP(평균판매가격)는 메모리 가격 사이클 파악에 활용된다고 설명됩니다.'),
(4, 19, '05', '반도체 Capex 역할', '반도체 산업에서 Capex(설비투자) 지표의 역할로 맞는 것은?', 'DRAM 현물가 선행 파악', '메모리 가격 사이클 추적', '공장 가동 효율 측정', '차세대 투자 방향 파악', 3, '문서에서 Capex(설비투자)는 차세대 투자 방향을 파악하는 데 활용된다고 설명합니다.'),
(4, 20, '05', '2차전지 팩 가격 단위', '2차전지 배터리 팩 가격 지표의 단위로 맞는 것은?', 'Wh/kg', '$/kWh', 'EV%', '원/ton', 1, '문서 표에서 2차전지 배터리 팩 가격 단위는 $/kWh로 제시됩니다.'),
(4, 21, '05', '2차전지 에너지 밀도', '2차전지 에너지 밀도(Wh/kg) 지표가 나타내는 것은?', '원가 경쟁력', '기술 우위', 'EV 수요 성장 모멘텀', '리튬 가격 변동 선행', 1, '문서에서 에너지 밀도(Wh/kg)는 기술 우위를 나타내는 지표로 설명됩니다.'),
(4, 22, '05', '바이오 R&D 지표', '바이오 R&D 비용/매출 비율이 나타내는 것은?', '특허 만료 시점 파악', '임상 성공 확률', '연구 집중도', 'FDA 허가 리스크', 2, '문서에서 바이오 R&D 비용/매출 비율은 연구 집중도를 나타내는 지표로 설명됩니다.'),
(4, 23, '05', '바이오 특허 만료 활용', '바이오 산업에서 특허 만료일 지표를 추적하는 주된 이유는?', '임상 파이프라인 단계 확인', '제네릭 경쟁 진입 시점 파악', 'FDA 허가 가능성 예측', 'R&D 집중도 측정', 1, '문서에서 특허 만료일은 제네릭 경쟁 진입 시점을 파악하는 데 활용된다고 설명됩니다.'),
(4, 24, '05', '섹터 ETF 티커', '문서의 섹터 비교 API에서 SOXX가 대표하는 섹터는?', '에너지', '금융', '헬스케어', '반도체', 3, '문서 코드 주석에서 SOXX는 반도체 ETF로 명시되어 있습니다.'),
(4, 25, '05', '표준 스키마 source 컬럼', '문서의 표준 데이터셋 스키마에서 데이터 출처를 나타내는 컬럼은?', 'period', 'unit', 'source', 'metric', 2, '문서 표준 스키마 표에서 source 컬럼은 DART, SEC, YFINANCE 같은 데이터 출처를 나타냅니다.'),
(4, 26, '05', '삼성전자 DART corp_code', '문서에서 삼성전자의 DART corp_code는?', '00164779', '00126380', '0001045810', '0000050863', 1, '문서 코드에서 삼성전자의 DART corp_code는 00126380으로 정의되어 있습니다.'),
(4, 27, '05', 'SEC EDGAR 필수 헤더', 'SEC EDGAR companyfacts API 요청 시 문서에서 반드시 포함하라고 안내한 HTTP 헤더는?', 'Authorization', 'API-Key', 'User-Agent', 'Content-Type', 2, '문서에서 SEC companyfacts API 요청 시 User-Agent를 명확히 넣는 것이 좋다고 안내합니다.'),
(4, 28, '05', '산업 대시보드 API', '문서에서 산업별 데이터·차트·점수를 한꺼번에 반환하는 API 엔드포인트는?', 'GET /api/industry/sources', 'GET /api/industry/companies', 'POST /api/industry/dashboard', 'POST /api/industry/report.pdf', 2, '문서 API 설계 표에서 /api/industry/dashboard는 가격·재무·SWOT·5 Forces·수명주기 대시보드를 반환하는 POST 엔드포인트입니다.'),
(4, 29, '05', 'API 응답 경고', '문서 산업 대시보드 API 응답 예시의 warnings 항목에 포함된 내용은?', '데이터 수집 속도 제한 초과 경고', 'DART와 SEC의 회계 기준 및 통화가 달라 직접 비교 시 조정 필요', '반도체 가동률 정보 누락', 'yfinance API 키 만료', 1, '응답 예시의 warnings에 DART와 SEC의 회계 기준 및 통화가 달라 직접 비교 시 환율/회계 기준 조정이 필요하다는 경고가 포함되어 있습니다.'),
(4, 30, '05', 'PDF 리포트 5페이지', 'PDF 리포트 5페이지(결론과 유의사항)에 포함되는 내용이 아닌 것은?', '투자 아이디어', '리스크', '데이터 한계', '1년 누적 수익률 비교 차트', 3, '문서에서 5페이지(결론과 유의사항)는 투자 아이디어, 리스크, 데이터 한계로 구성됩니다. 1년 누적 수익률 비교 차트는 3페이지(기업·ETF 비교)의 내용입니다.');
